import{_ as t,o,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Virtualizing with Proxmox® VE","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/networking/pfsense/virtualizing-with-proxmox-r-ve.md","filePath":"software-engineering/networking/pfsense/virtualizing-with-proxmox-r-ve.md"}'),n={name:"software-engineering/networking/pfsense/virtualizing-with-proxmox-r-ve.md"};function a(s,e,l,p,c,g){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="virtualizing-with-proxmox®-ve" tabindex="-1">Virtualizing with Proxmox® VE <a class="header-anchor" href="#virtualizing-with-proxmox®-ve" aria-label="Permalink to &quot;Virtualizing with Proxmox® VE&quot;">​</a></h1><p><a href="https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html" target="_blank" rel="noreferrer">https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html</a></p><p>This following article is about building and running pfSense® software on a virtual machine under Proxmox Virtual Environment (VE). The guide also applies to any newer Proxmox VE version. Article covers Proxmox VE networking setup and firewall virtual machine setup process. The guide does not cover how to install Proxmox VE.</p><p>A basic, working, virtual machine will exist by the end of this article.</p><h2 id="assumptions¶" tabindex="-1">Assumptions<a href="https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#assumptions" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#assumptions¶" aria-label="Permalink to &quot;Assumptions[¶](https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#assumptions)&quot;">​</a></h2><ul><li>Proxmox VE host is up and running</li><li>Host has at least two network interfaces available for WAN and LAN.</li><li>pfSense software ISO image is present on the Proxmox VE host</li></ul><h3 id="basic-proxmox-ve-networking¶" tabindex="-1">Basic Proxmox VE networking<a href="https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#basic-proxmox-ve-networking" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#basic-proxmox-ve-networking¶" aria-label="Permalink to &quot;Basic Proxmox VE networking[¶](https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#basic-proxmox-ve-networking)&quot;">​</a></h3><p>First create two Linux Bridges on Proxmox VE, which will be used for LAN and WAN on the firewall VM.</p><ul><li>Select the host from the server view</li><li>Navigate to <strong>System &gt; Network</strong></li></ul><p>This example uses <code>enp4s0</code> and <code>enp5s0</code> interfaces for the firewall, while <code>enp3s0</code> is for Proxmox VE management. The naming of interfaces will vary depending on the hardware involved (interface type, bus location, etc.).</p><figure><img src="https://docs.netgate.com/pfsense/en/latest/_images/pve-01-network.png" alt=""><figcaption></figcaption></figure><ul><li>Click <strong>Create</strong></li><li>Select Linux Bridge</li><li>Enter <code>enp4s0</code> under <strong>Bridge ports</strong></li></ul><figure><img src="https://docs.netgate.com/pfsense/en/latest/_images/pve-02-vmbr1.png" alt=""><figcaption></figcaption></figure><p>Repeat the process to add another Linux Bridge, this time add <code>enp5s0</code> under <strong>Bridge ports</strong>.</p><figure><img src="https://docs.netgate.com/pfsense/en/latest/_images/pve-03-vmbr2.png" alt=""><figcaption></figcaption></figure><ul><li>Click <strong>Apply Configuration</strong> to configure the new interfaces in the OS</li><li>Click <strong>Yes</strong> to confirm the action</li></ul><p>Proxmox VE networking should now display two Linux bridges like on the following screenshot.</p><p>Note</p><p>If the interfaces do not show as <strong>Active</strong>, reboot the Proxmox VE host.</p><figure><img src="https://docs.netgate.com/pfsense/en/latest/_images/pve-04-bridges.png" alt=""><figcaption></figcaption></figure><h3 id="creating-a-virtual-machine¶" tabindex="-1">Creating a Virtual Machine<a href="https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#creating-a-virtual-machine" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#creating-a-virtual-machine¶" aria-label="Permalink to &quot;Creating a Virtual Machine[¶](https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#creating-a-virtual-machine)&quot;">​</a></h3><p>After creating WAN and LAN Linux bridges, now proceed to create a new virtual machine.</p><ul><li><p>Click <strong>Create VM</strong> from the top right section to display the new virtual machine wizard</p></li><li><p>Navigate to the <strong>General</strong> tab</p></li><li><p>Enter a <strong>Name</strong> for the VM (e.g. <code>firewall</code>)</p></li><li><p>Navigate to the <strong>OS</strong> tab</p></li><li><p>Set the following options:</p><p>Use CD/DVD disc image file:</p><p>Selected</p><p>Storage:</p><p><em>local</em></p><p>ISO image:</p><p>Select the previously uploaded ISO image</p><p>Guest OS Type:</p><p><strong>Other</strong></p></li><li><p>Navigate to the <strong>System</strong> tab</p></li><li><p>Set the following options:</p><p>Graphic card:</p><p><em>SPICE</em></p><p>Note</p><p>The <a href="https://pve.proxmox.com/wiki/SPICE" target="_blank" rel="noreferrer">SPICE</a> console uses less CPU when idle and supports more advanced console features than the default console. It is compatible with the VNC Proxmox VE console as well as the more advanced <a href="https://www.spice-space.org/download.html" target="_blank" rel="noreferrer">virt-viewer</a> console application.</p></li><li><p>Navigate to the <strong>Hard Disk</strong> tab</p></li><li><p>Set the following options:</p><p>Bus/Device:</p><p><strong>VirtIO Block</strong></p><p>Disk Size:</p><p>Enter an appropriate disk size, no less than <code>8</code> GB.</p></li><li><p>Navigate to the <strong>CPU</strong> tab</p></li><li><p>Set the following options:</p><p>Socket:</p><p><code>1</code></p><p>Cores:</p><p><code>1</code> or more cores as needed</p><p>Type:</p><p><strong>Host</strong> to match the CPU on the hypervisor hardware.</p><p>Extra CPU Flags:</p><p>These settings adjust the CPU capabilities and behavior of the guest. If using <strong>Host</strong> for <strong>Type</strong> these can likely be left at the default.</p><p>When setting a CPU type other than <strong>Host</strong>, consider setting the <strong>AES</strong> flag to <strong>+</strong> (<strong>On</strong>) which allows the guest to use AES-NI (<a href="https://docs.netgate.com/pfsense/en/latest/hardware/cryptographic-accelerators.html" target="_blank" rel="noreferrer">Cryptographic Accelerator Support</a>).</p></li><li><p>Navigate to the <strong>Memory</strong> tab</p></li><li><p>Set the following options:</p><p>Memory:</p><p>At least <code>1024</code> MB</p></li><li><p>Navigate to the <strong>Network</strong> tab</p></li><li><p>Set the following options:</p><p>Bridge:</p><p><em>vmbr1</em></p><p>Model:</p><p><em>VirtIO (paravirtualized)</em></p></li><li><p>Navigate to the <strong>Confirm</strong> tab</p></li><li><p>Review the settings and make any final corrections if necessary</p></li><li><p>Click <strong>Finish</strong></p></li><li><p>Wait for the VM creation process to finish</p></li></ul><p>Now add another network adapter to the VM:</p><ul><li><p>Expand the <strong>Server View</strong> list on the left to show the contents under <strong>Datacenter</strong> and the name of this hypervisor node (e.g. <strong>pve</strong>, <strong>proxmox</strong>, etc.)</p></li><li><p>Select the newly created virtual machine from list</p></li><li><p>Click <strong>Hardware</strong> in the right pane</p></li><li><p>Click <strong>Add</strong></p></li><li><p>Click <strong>Network Device</strong></p></li><li><p>Set the following options:</p><p>Bridge:</p><p><em>vmbr2</em></p><p>Model:</p><p><em>VirtIO (paravirtualized)</em></p></li><li><p>Click <strong>Add</strong></p></li></ul><p>Review the hardware list for the VM and confirm it now contains two network interfaces.</p><h3 id="starting-and-configuring-the-virtual-machine¶" tabindex="-1">Starting and configuring the virtual machine<a href="https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#starting-and-configuring-the-virtual-machine" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#starting-and-configuring-the-virtual-machine¶" aria-label="Permalink to &quot;Starting and configuring the virtual machine[¶](https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#starting-and-configuring-the-virtual-machine)&quot;">​</a></h3><p>After creating a new virtual machine and adding network interfaces, it is time to start the virtual machine.</p><ul><li><p>Expand the <strong>Server View</strong> list on the left to show the contents under <strong>Datacenter</strong> and the name of this hypervisor node (e.g. <strong>pve</strong>, <strong>proxmox</strong>, etc.)</p></li><li><p>Select the newly created virtual machine from list</p></li><li><p>Click <strong>Start</strong></p></li><li><p>Click <strong>Console</strong> on the left, under <strong>Summary</strong></p><p>Note</p><p>The <strong>Console</strong> button at the top will launch the console in a new window, which depending on the settings may require an additional client installation such as <a href="https://www.spice-space.org/download.html" target="_blank" rel="noreferrer">virt-viewer</a>.</p></li></ul><p>When the VM starts it will boot into the installer automatically. From there, follow the installation steps as usual, and reboot when finished.</p><p>See also</p><p>See <a href="https://docs.netgate.com/pfsense/en/latest/install/install-walkthrough.html" target="_blank" rel="noreferrer">Installation Walkthrough</a> for a detailed walkthrough of the installation process.</p><p>After the virtual machine reboots, the console will stop at an interfaces assignment prompt.</p><ul><li>Type <code>n</code> and press <code>Enter</code> to skip VLAN configuration</li><li>Enter <code>vtnet0</code> for WAN</li><li>Enter <code>vtnet1</code> for LAN</li><li>Press <code>Enter</code> if prompted for additional interfaces</li><li>Type <code>y</code> and press <code>Enter</code> to complete the interface assignment</li></ul><p>After interfaces have been assigned, the VM will complete the boot process.</p><h3 id="disable-hardware-checksums-with-proxmox-ve-virtio¶" tabindex="-1">Disable Hardware Checksums with Proxmox VE VirtIO<a href="https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#disable-hardware-checksums-with-proxmox-ve-virtio" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#disable-hardware-checksums-with-proxmox-ve-virtio¶" aria-label="Permalink to &quot;Disable Hardware Checksums with Proxmox VE VirtIO[¶](https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#disable-hardware-checksums-with-proxmox-ve-virtio)&quot;">​</a></h3><p>When using VirtIO interfaces in Proxmox VE, network interface hardware checksum offloading <strong>must</strong> be disabled. Current versions of pfSense software attempt to disable this automatically for <code>vtnet</code> interfaces, but the best practice is to double check the setting in case changes in Proxmox VE result in the automatic process failing.</p><p>Warning</p><p>Do not skip this step, otherwise the virtual machine will not properly pass traffic. Accessing the firewall may be sluggish at first, but changing this setting will correct that as well.</p><p>After the installation and interfaces assignment processes are complete, connect to the assigned LAN port from another computer or VM on the LAN-side bridge.</p><p>To disable hardware checksum offload:</p><ul><li>Navigate to <strong>System &gt; Advanced</strong>, <strong>Networking</strong> tab</li><li>Locate the <strong>Networking Interfaces</strong> section</li><li>Check <strong>Disable hardware checksum offload</strong></li><li>Click Save</li><li>Reboot the firewall from <strong>Diagnostics &gt; Reboot</strong> or the console menu</li></ul><figure><img src="https://docs.netgate.com/pfsense/en/latest/_images/pve-05-checksumoffload.png" alt=""><figcaption></figcaption></figure><p><strong>Congratulations, the virtual machine installation and configuration on Proxmox VE is now complete.</strong></p><h3 id="booting-uefi¶" tabindex="-1">Booting UEFI<a href="https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#booting-uefi" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#booting-uefi¶" aria-label="Permalink to &quot;Booting UEFI[¶](https://docs.netgate.com/pfsense/en/latest/recipes/virtualize-proxmox-ve.html#booting-uefi)&quot;">​</a></h3><p>pfSense software can boot UEFI in a Proxmox VE guest but doing so requires a few extra steps.</p><p>When creating the VM:</p><ul><li>Set <strong>Machine</strong> to <strong>q35</strong></li><li>Set <strong>BIOS</strong> to <strong>OVMF (UEFI)</strong></li><li>Add an EFI disk when prompted</li><li>Pick the storage for the EFI disk, other settings can remain at defaults</li></ul><p>Note</p><p>An existing non-UEFI VM can be reconfigured to boot UEFI with these settings on its <strong>Hardware</strong> but the process is more error prone. For example, the EFI disk is a separate manual process and not semi-automated as it is when creating a VM.</p><p>After creating the VM:</p><ul><li><p>Edit the VM Hardware and add a serial port device</p><p>Note</p><p>On some versions of pfSense software the EFI boot process for a ProxMox VE VM works more reliably with a serial port present in the VM hardware, even if the OS is not actively using the port.</p></li></ul><p>On the first boot, go into the boot settings and disable secure boot:</p><ul><li>Hit <code>Esc</code> while the boot splash screen is visible</li><li>Select <strong>Device Manager</strong></li><li>Select <strong>Secure Boot Configuration</strong></li><li>Uncheck <strong>Attempt Secure Boot</strong></li><li>Press <code>F10</code> to save</li><li>Press <code>Esc</code> to exit</li><li>Reset the VM</li></ul><p>With secure boot disabled the VM can now boot with UEFI from the ISO as well as after installation.</p><p>\\</p>',56)])])}const m=t(n,[["render",a]]);export{d as __pageData,m as default};
